import{_ as a,o as r,c as t,a4 as o}from"./chunks/framework.BY9PERBP.js";const b=JSON.parse('{"title":"Interface: GridDataSource · datagrid","description":"","frontmatter":{"title":"Interface: GridDataSource<T> · datagrid"},"headers":[],"relativePath":"api/datagrid/interfaces/GridDataSource.md","filePath":"api/datagrid/interfaces/GridDataSource.md"}'),d={name:"api/datagrid/interfaces/GridDataSource.md"};function s(c,e,i,n,l,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<p><a href="./../">@jsvision/datagrid</a> / GridDataSource</p><h1 id="interface-griddatasource-t" tabindex="-1">Interface: GridDataSource&lt;T&gt; <a class="header-anchor" href="#interface-griddatasource-t" aria-label="Permalink to &quot;Interface: GridDataSource\\&lt;T\\&gt;&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L22" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:22</a></p><p>The read/mutate seam the grid body binds to. In-memory and windowed/server sources implement this same shape, so the body is source-agnostic. Only <code>rowKey</code>/<code>length</code>/<code>rowAt</code> are exercised in the read-only foundation; the optional push-down and windowing members are declared for later releases.</p><p><code>rowAt</code> returns <code>undefined</code> for an out-of-range or not-yet-loaded index (a windowed source may not have the row yet); an in-memory source always has every in-range row.</p><h2 id="type-parameters" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h2><h3 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h3><p><code>T</code></p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="rowkey" tabindex="-1">rowKey <a class="header-anchor" href="#rowkey" aria-label="Permalink to &quot;rowKey&quot;">​</a></h3><blockquote><p><strong>rowKey</strong>: (<code>row</code>) =&gt; <code>string</code> | <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L24" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:24</a></p><p>Stable identity for a row (required).</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="row" tabindex="-1">row <a class="header-anchor" href="#row" aria-label="Permalink to &quot;row&quot;">​</a></h5><p><code>T</code></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>string</code> | <code>number</code></p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="complete" tabindex="-1">complete()? <a class="header-anchor" href="#complete" aria-label="Permalink to &quot;complete()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>complete</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L58" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:58</a></p><p>Whether every row is loaded in memory. Omit it (or return <code>true</code>) for an eager in-memory source, so a footer aggregate renders a clean grand total. A windowed/server source that has loaded only part of the dataset returns <code>false</code>, and the footer labels its aggregates <code>&quot;(loaded)&quot;</code> — a total over the loaded set is never passed off as a whole-dataset grand total.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="distinct" tabindex="-1">distinct()? <a class="header-anchor" href="#distinct" aria-label="Permalink to &quot;distinct()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>distinct</strong>(<code>columnId</code>): <code>Promise</code>&lt;<a href="./DistinctResult.html"><code>DistinctResult</code></a>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L51" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:51</a></p><p>Distinct formatted labels for a column, for value-list filtering (a later release). Returns the labels plus an optional <code>truncated</code> flag so a bounded/windowed source can disclose a capped list instead of silently under-reporting.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="columnid" tabindex="-1">columnId <a class="header-anchor" href="#columnid" aria-label="Permalink to &quot;columnId&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<a href="./DistinctResult.html"><code>DistinctResult</code></a>&gt;</p><hr><h3 id="ensurerange" tabindex="-1">ensureRange()? <a class="header-anchor" href="#ensurerange" aria-label="Permalink to &quot;ensureRange()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>ensureRange</strong>(<code>start</code>, <code>end</code>): <code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L41" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:41</a></p><p>Prefetch a window of rows (windowed sources; a later release).</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="start" tabindex="-1">start <a class="header-anchor" href="#start" aria-label="Permalink to &quot;start&quot;">​</a></h5><p><code>number</code></p><h5 id="end" tabindex="-1">end <a class="header-anchor" href="#end" aria-label="Permalink to &quot;end&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="insert" tabindex="-1">insert()? <a class="header-anchor" href="#insert" aria-label="Permalink to &quot;insert()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>insert</strong>(<code>row</code>, <code>at?</code>): <code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L34" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:34</a></p><p>Insert a row at a <strong>source-array</strong> index (append when <code>at</code> is omitted). Optional — a source that omits it is read-only, so the grid can never add through it. The row must already carry its own <code>rowKey</code> (the caller owns key generation). A windowed/server source uses this callback to persist.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="row-1" tabindex="-1">row <a class="header-anchor" href="#row-1" aria-label="Permalink to &quot;row&quot;">​</a></h5><p><code>T</code></p><h5 id="at" tabindex="-1">at? <a class="header-anchor" href="#at" aria-label="Permalink to &quot;at?&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="length" tabindex="-1">length() <a class="header-anchor" href="#length" aria-label="Permalink to &quot;length()&quot;">​</a></h3><blockquote><p><strong>length</strong>(): <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L26" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:26</a></p><p>Total row count (best-known for a windowed source).</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>number</code></p><hr><h3 id="remove" tabindex="-1">remove()? <a class="header-anchor" href="#remove" aria-label="Permalink to &quot;remove()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>remove</strong>(<code>keys</code>): <code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L39" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:39</a></p><p>Remove rows by key. Optional — a source that omits it is read-only, so the grid can never delete through it. Keys not present are ignored. A windowed/server source uses this callback to persist.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="keys" tabindex="-1">keys <a class="header-anchor" href="#keys" aria-label="Permalink to &quot;keys&quot;">​</a></h5><p>readonly <a href="./../type-aliases/Key.html"><code>Key</code></a>[]</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="revision" tabindex="-1">revision()? <a class="header-anchor" href="#revision" aria-label="Permalink to &quot;revision()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>revision</strong>(): <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L67" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:67</a></p><p>A reactive revision counter for a windowed/async source: the grid reads it inside its display derivation, so a bump (a fetched window has landed) re-derives the display and repaints the newly-loaded rows. It <strong>must</strong> be a tracked signal read (e.g. the getter of a <code>signal&lt;number&gt;</code>), not a plain counter — a non-reactive read never subscribes, so the grid would never repaint on resolve. Omit it for an eager in-memory source (its rows signal already drives repaint); the grid&#39;s read is then inert.</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>number</code></p><hr><h3 id="rowat" tabindex="-1">rowAt() <a class="header-anchor" href="#rowat" aria-label="Permalink to &quot;rowAt()&quot;">​</a></h3><blockquote><p><strong>rowAt</strong>(<code>index</code>): <code>T</code> | <code>undefined</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L28" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:28</a></p><p>The row at a display-ordered index, or <code>undefined</code> when out of range / not yet loaded.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="index" tabindex="-1">index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;index&quot;">​</a></h5><p><code>number</code></p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>T</code> | <code>undefined</code></p><hr><h3 id="setfilter" tabindex="-1">setFilter()? <a class="header-anchor" href="#setfilter" aria-label="Permalink to &quot;setFilter()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>setFilter</strong>(<code>model</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L45" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:45</a></p><p>Push filtering down to the source; omit for client-side filtering (a later release).</p><h4 id="parameters-6" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-6" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="model" tabindex="-1">model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;model&quot;">​</a></h5><p><a href="./../type-aliases/FilterModel.html"><code>FilterModel</code></a></p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="setsort" tabindex="-1">setSort()? <a class="header-anchor" href="#setsort" aria-label="Permalink to &quot;setSort()?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>setSort</strong>(<code>keys</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/datagrid/src/data-source.ts#L43" target="_blank" rel="noreferrer">datagrid/src/data-source.ts:43</a></p><p>Push sort down to the source; omit for client-side sorting (a later release).</p><h4 id="parameters-7" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-7" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="keys-1" tabindex="-1">keys <a class="header-anchor" href="#keys-1" aria-label="Permalink to &quot;keys&quot;">​</a></h5><p><a href="./SortKey.html"><code>SortKey</code></a>[]</p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p>',113)])])}const p=a(d,[["render",s]]);export{b as __pageData,p as default};
